+) -> DifferentialValidationLogEntry {
+    DifferentialValidationLogEntry {
+        packet_id: result.packet_id.clone(),
+        case_id: result.case_id.clone(),
+        mode: result.mode,
+        trace_id: if result.trace_id.is_empty() {
